import React, { useMemo, useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";

// ── UI primitives ─────────────────────────────────────────────
function Card({ className = "", children }) {
  return <div className={`bg-white ${className}`}>{children}</div>;
}
function CardContent({ className = "", children }) {
  return <div className={className}>{children}</div>;
}
function Progress({ value = 0, className = "", color = "bg-blue-500" }) {
  return (
    <div className={`w-full overflow-hidden rounded-full bg-slate-700/40 ${className}`}>
      <div className={`h-full ${color} transition-all duration-300`}
        style={{ width: `${Math.max(0, Math.min(100, value))}%` }} />
    </div>
  );
}
function Input({ className = "", ...props }) {
  return <input className={`w-full border px-3 py-2 outline-none focus:ring-2 focus:ring-blue-400 ${className}`} {...props} />;
}

