// UTILITY FUNCTIONS
// ══════════════════════════════════════════════════════════
function shuffleArray(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function buildPack(mode, realm) {
  return shuffleArray(QUESTION_BANK.filter(item => item.mode === mode && item.realm === realm)).slice(0, 15);
}

// ── Sound engine ──────────────────────────────────────────
function useSound() {
  const ctx = useRef(null);
  const nodes = useRef([]);
  const active = useRef(false);

  function stop() {
    nodes.current.forEach(n => { try { n.stop(); } catch(e) {} });
    nodes.current = [];
    active.current = false;
  }

  function calm() {
    if (active.current) return;
    try {
      if (!ctx.current) ctx.current = new (window.AudioContext || window.webkitAudioContext)();
      const ac = ctx.current;
      active.current = true;
      const buf = ac.createBuffer(1, ac.sampleRate * 4, ac.sampleRate);
      const d = buf.getChannelData(0);
      for (let i = 0; i < d.length; i++) d[i] = Math.random() * 2 - 1;
      const src = ac.createBufferSource(); src.buffer = buf; src.loop = true;
      const flt = ac.createBiquadFilter(); flt.type = "lowpass"; flt.frequency.value = 400;
      const g = ac.createGain(); g.gain.value = 0.025;
      src.connect(flt); flt.connect(g); g.connect(ac.destination); src.start();
      nodes.current.push(src);
      [[110, 0.008], [220, 0.005], [55, 0.01]].forEach(([freq, gain]) => {
        const o = ac.createOscillator(); const og = ac.createGain();
        o.type = "sine"; o.frequency.value = freq; og.gain.value = gain;
        o.connect(og); og.connect(ac.destination); o.start();
        nodes.current.push(o);
      });
    } catch(e) {}
  }

  function competitive() {
    if (active.current) return;
    try {
      if (!ctx.current) ctx.current = new (window.AudioContext || window.webkitAudioContext)();
      const ac = ctx.current;
      active.current = true;
      // Electric blue pulse — sine wave clusters
      [[220, 3, 0.018], [440, 6, 0.012], [880, 12, 0.007]].forEach(([freq, lfoFreq, gain]) => {
        const o = ac.createOscillator(); const g = ac.createGain();
        const lfo = ac.createOscillator(); const lg = ac.createGain();
        o.type = "sine"; o.frequency.value = freq;
        lfo.type = "sine"; lfo.frequency.value = lfoFreq;
        lg.gain.value = 0.012; g.gain.value = gain;
        lfo.connect(lg); lg.connect(g.gain);
        o.connect(g); g.connect(ac.destination);
        lfo.start(); o.start();
        nodes.current.push(lfo, o);
      });
      // White noise layer
      const buf = ac.createBuffer(1, ac.sampleRate * 2, ac.sampleRate);
      const d = buf.getChannelData(0);
      for (let i = 0; i < d.length; i++) d[i] = Math.random() * 2 - 1;
      const src = ac.createBufferSource(); src.buffer = buf; src.loop = true;
      const flt = ac.createBiquadFilter(); flt.type = "bandpass"; flt.frequency.value = 3000; flt.Q.value = 0.6;
      const g = ac.createGain(); g.gain.value = 0.008;
      src.connect(flt); flt.connect(g); g.connect(ac.destination); src.start();
      nodes.current.push(src);
    } catch(e) {}
  }

  useEffect(() => () => stop(), []);
  return { calm, competitive, stop };
}

// ── Toggle component ──────────────────────────────────────
function Toggle({ value, onChange, left, lv, right, rv, comp }) {
  return (
    <div className={`inline-flex rounded-2xl border p-1 ${comp
      ? "border-blue-500/40 bg-slate-900/80"
      : "border-emerald-200 bg-white/80"}`}>
      {[{l: left, v: lv}, {l: right, v: rv}].map(({l, v}) => (
        <button key={v} onClick={() => onChange(v)}
          className={`rounded-xl px-3 py-2 text-sm font-semibold transition-all ${
            value === v
              ? (comp ? "bg-blue-600 text-white shadow-[0_0_12px_rgba(59,130,246,0.6)]" : "bg-emerald-600 text-white")
              : (comp ? "text-blue-300 hover:bg-blue-900/40" : "text-slate-600 hover:bg-green-50")
          }`}>{l}</button>
      ))}
    </div>
  );
}

