// ── Timer hook ────────────────────────────────────────────
function useTimer(active, onExpire) {
  const [timeLeft, setTimeLeft] = useState(60);
  const intervalRef = useRef(null);

  useEffect(() => {
    if (!active) { clearInterval(intervalRef.current); return; }
    setTimeLeft(60);
    intervalRef.current = setInterval(() => {
      setTimeLeft(t => {
        if (t <= 1) { clearInterval(intervalRef.current); onExpire(); return 0; }
        return t - 1;
      });
    }, 1000);
    return () => clearInterval(intervalRef.current);
  }, [active]);

  const reset = () => { clearInterval(intervalRef.current); setTimeLeft(60); };
  return { timeLeft, reset };
}

